function loadAll(): Record<string, object> {
  try {
    if (!fs.existsSync(PREFS_FILE)) return {};
    const raw = fs.readFileSync(PREFS_FILE, "utf-8").trim();
    return raw ? JSON.parse(raw) : {};
  } catch { return {}; }
}

